# Verify temperature bump logic
def calc_temp(temperature, attempt):
    if attempt == 0:
        return temperature
    bump = 0.2 * attempt
    return (temperature + bump if temperature + bump <= 1.0
            else max(0.0, temperature - bump))

# Test with various input temperatures
for temp_in in [0.0, 0.5, 0.9, 1.0]:
    print(f"\nInput temperature: {temp_in}")
    for attempt in range(1, 4):
        t = calc_temp(temp_in, attempt)
        print(f"  Attempt {attempt}: {t:.2f} (valid: {0.0 <= t <= 1.0})")
        if t < 0.0 or t > 1.0:
            print(f"    ERROR: Out of range!")
